    greeting = f"/ {greeting} /"
elif style == "star":
    greeting = f"★ {greeting} ★"
elif style == "pipe":
    greeting = f"| {greeting} |"
elif style == "arrow":
    greeting = f"==> {greeting} <=="
elif style == "curly":
    greeting = f"{{ {greeting} }}"
elif style == "hash":
    greeting = f"# {greeting} #"
elif style == "tilde":
    greeting = f"~ {greeting} ~"
elif style == "neon":
    greeting = f"✨ {greeting} ✨"
elif style == "ghost":
    greeting = f"👻 {greeting} 👻"

for _ in range(repeat_count):
    if boxed:
        border = "+" + ("-" * (len(greeting) + 2)) + "+"
        print(border)
        print(f"| {greeting} |")
        print(border)
    else:
        print(greeting)
